const $=(q,r=document)=>r.querySelector(q);const $$=(q,r=document)=>Array.from(r.querySelectorAll(q));
function initAscend(){const c=$('#ascend');if(!c)return;const ctx=c.getContext('2d');let w,h,dpr,pts=[];const make=()=>{dpr=Math.min(devicePixelRatio||1,2);w=c.width=Math.floor(innerWidth*dpr);h=c.height=Math.floor(innerHeight*dpr);c.style.width=innerWidth+'px';c.style.height=innerHeight+'px';pts=Array.from({length:120},()=>({x:Math.random()*w,y:Math.random()*h,r:(Math.random()*1.8+0.7)*dpr,v:(Math.random()*0.55+0.25)*dpr,a:Math.random()*6.28,hue:Math.random()}));};const draw=()=>{ctx.clearRect(0,0,w,h);for(const p of pts){p.y-=p.v;p.x+=Math.sin(p.a+=.012)*.12*dpr;if(p.y<-18*dpr){p.y=h+10*dpr;p.x=Math.random()*w}ctx.beginPath();ctx.arc(p.x,p.y,p.r,0,6.28);ctx.fillStyle=p.hue>.68?'rgba(255,230,129,.65)':p.hue>.35?'rgba(113,255,216,.62)':'rgba(135,166,255,.55)';ctx.fill();ctx.fillRect(p.x,p.y+p.r+2*dpr,.6*dpr,18*dpr)}requestAnimationFrame(draw)};addEventListener('resize',make,{passive:true});make();draw();}
async function initAtlas(){const root=$('[data-atlas]');if(!root)return;const res=await fetch('site-navigation-v37.json');const data=await res.json();const search=$('#atlasSearch');const chips=$$('#atlasChips button');const groups=$('#atlasGroups');const journeys=$('#journeyCards');if(journeys){journeys.innerHTML=data.journeys.map(j=>`<article class="card path-card"><div class="tag">${j.duration}</div><h3>${j.title}</h3><p>${j.summary}</p><div class="step-list">${j.steps.map((s,i)=>{const item=findItem(data,s);return `<a href="${s}"><span>${i+1}. ${item?.title||s}</span><span>→</span></a>`}).join('')}</div></article>`).join('')}
function findItem(d,href){for(const s of d.sections){const f=s.items.find(i=>i.href===href);if(f)return f}return d.primary.find(i=>i.href===href)}
function render(){const term=(search?.value||'').toLowerCase().trim();const active=chips.find(c=>c.classList.contains('active'))?.dataset.filter||'all';groups.innerHTML=data.sections.map(sec=>{const items=sec.items.filter(i=>(active==='all'||sec.id===active||i.audience.toLowerCase()===active)&&(!term||`${i.title} ${i.summary} ${i.audience} ${sec.title}`.toLowerCase().includes(term)));if(!items.length)return '';return `<section class="demo-group" id="${sec.id}"><div class="kicker">${sec.title}</div><h2>${sec.summary}</h2><div class="demo-grid">${items.map(i=>`<a class="demo-card" href="${i.href}"><div class="demo-meta"><span>${i.audience}</span><span>${i.time}</span></div><h4>${i.title}</h4><p>${i.summary}</p></a>`).join('')}</div></section>`}).join('')||'<div class="notice">No matching routes. Clear the search or choose another filter.</div>'}
chips.forEach(chip=>chip.addEventListener('click',()=>{chips.forEach(c=>c.classList.remove('active'));chip.classList.add('active');render()}));search?.addEventListener('input',render);render();}
async function initHomeLibrary(){const root=$('[data-home-library]');if(!root)return;const res=await fetch('site-navigation-v37.json');const data=await res.json();const box=$('#homeDemoGroups');box.innerHTML=data.sections.map(sec=>`<section class="demo-group" id="${sec.id}"><div class="kicker">${sec.title}</div><h3 style="font-size:32px;margin:12px 0 12px">${sec.summary}</h3><div class="demo-grid">${sec.items.map(i=>`<a class="demo-card" href="${i.href}"><div class="demo-meta"><span>${i.audience}</span><span>${i.time}</span></div><h4>${i.title}</h4><p>${i.summary}</p></a>`).join('')}</div></section>`).join('')}
function navSelect(){const s=$('.mobile-select');if(s)s.addEventListener('change',()=>{if(s.value)location.href=s.value})}
initAscend();initAtlas();initHomeLibrary();navSelect();
